/* ════════════════════════════════════════════ */
/* ══      JEU DE LUMIÈRES — PLEIN SITE      ══ */
/* ════════════════════════════════════════════ */

/* Halo extérieur du site */
@keyframes jl-halo {
  0%,  44% { box-shadow: 0 0 100px 40px #22c55e, 0 0 200px 80px rgba(34,197,94,0.5); }
  45%,  49% { box-shadow: 0 0 0px 0px transparent; }
  50%,  94% { box-shadow: 0 0 100px 40px #ef4444, 0 0 200px 80px rgba(239,68,68,0.5); }
  95%,  99% { box-shadow: 0 0 0px 0px transparent; }
  100% { box-shadow: 0 0 100px 40px #22c55e, 0 0 200px 80px rgba(34,197,94,0.5); }
}

/* Overlay couleur plein écran */
@keyframes jl-overlay {
  0%,  44% { background: rgba(34, 197, 94, 0.15); }
  45%,  49% { background: rgba(0,0,0,0); }
  50%,  94% { background: rgba(239, 68, 68, 0.15); }
  95%,  99% { background: rgba(0,0,0,0); }
  100% { background: rgba(34, 197, 94, 0.15); }
}

/* Textes — lueur colorée */
@keyframes jl-texte {
  0%,  44% { text-shadow: 0 0 10px #22c55e, 0 0 25px rgba(34,197,94,0.7) !important; color: #4ade80 !important; }
  45%,  49% { text-shadow: none !important; color: inherit !important; }
  50%,  94% { text-shadow: 0 0 10px #ef4444, 0 0 25px rgba(239,68,68,0.7) !important; color: #f87171 !important; }
  95%,  99% { text-shadow: none !important; color: inherit !important; }
  100% { text-shadow: 0 0 10px #22c55e, 0 0 25px rgba(34,197,94,0.7) !important; color: #4ade80 !important; }
}

/* Boutons — couleur de fond */
@keyframes jl-bouton {
  0%,  44% { background: linear-gradient(135deg,#166534,#22c55e) !important; border-color: #22c55e !important; box-shadow: 0 0 18px rgba(34,197,94,0.9) !important; color: #fff !important; }
  45%,  49% { background: rgba(255,255,255,0.07) !important; box-shadow: none !important; }
  50%,  94% { background: linear-gradient(135deg,#991b1b,#ef4444) !important; border-color: #ef4444 !important; box-shadow: 0 0 18px rgba(239,68,68,0.9) !important; color: #fff !important; }
  95%,  99% { background: rgba(255,255,255,0.07) !important; box-shadow: none !important; }
  100% { background: linear-gradient(135deg,#166534,#22c55e) !important; border-color: #22c55e !important; box-shadow: 0 0 18px rgba(34,197,94,0.9) !important; color: #fff !important; }
}

/* Bordures cartes */
@keyframes jl-carte {
  0%,  44% { border-color: #22c55e !important; box-shadow: 0 0 14px rgba(34,197,94,0.6), inset 0 0 10px rgba(34,197,94,0.08) !important; }
  45%,  49% { border-color: rgba(255,255,255,0.1) !important; box-shadow: none !important; }
  50%,  94% { border-color: #ef4444 !important; box-shadow: 0 0 14px rgba(239,68,68,0.6), inset 0 0 10px rgba(239,68,68,0.08) !important; }
  95%,  99% { border-color: rgba(255,255,255,0.1) !important; box-shadow: none !important; }
  100% { border-color: #22c55e !important; box-shadow: 0 0 14px rgba(34,197,94,0.6), inset 0 0 10px rgba(34,197,94,0.08) !important; }
}

/* ── Application ── */

body {
  animation: jl-halo 10s step-end infinite;
}

body::after {
  content: '';
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 9998;
  animation: jl-overlay 10s step-end infinite;
}

h1, h2, h3, h4, h5, h6, p, span, label, td, th {
  animation: jl-texte 10s step-end infinite !important;
}

button {
  animation: jl-bouton 10s step-end infinite !important;
}

div[style*='border'], div[class*='card'], div[class*='panel'], section {
  animation: jl-carte 10s step-end infinite !important;
}
